class TreeNode {
    int val;
    TreeNode left;
    TreeNode right;
}

public TreeNode searchBST(TreeNode root, int val) {
    if (root == null || root.val == val)
        return root;
    return (root.val < val) ? searchBST(root.right, val) : searchBST(root.left, val);
}
```


